-- Tüm batch dosyalarından KPI verilerini yükle
INSERT INTO kpi_target_cards_detail (period, branchName, branchManager, bolgeSorumlusu, dimension, target, targetDescription, unit, source, frequency, weight, targetType, lowerLimit, targetValue, upperLimit, actualValue, score, weightedScore, createdAt, updatedAt) 
SELECT '2026/3' as period, branchName, branchManager, branchManager as bolgeSorumlusu, dimension, target, targetDescription, unit, source, frequency, weight, targetType, lowerLimit, targetValue, upperLimit, NULL, NULL, NULL, NOW(), NOW()
FROM (
  SELECT DISTINCT '2026/3' as period, 'BY İSTANBUL ÜMRANİYE' as branchName, 'ERDAL PÖRKLÜ' as branchManager, 'Finans' as dimension, 'Ciro /Hamburger Adedi' as target, 'Aylık Restoran Cirosu / Satılan Hamburger Adedi' as targetDescription, 'TL' as unit, 'Maliyet Raporu' as source, 'Aylık' as frequency, 15 as weight, 'Artan' as targetType, '4940000' as lowerLimit, '5200000' as targetValue, '5980000' as upperLimit
) t
WHERE NOT EXISTS (
  SELECT 1 FROM kpi_target_cards_detail 
  WHERE period = '2026/3' AND branchName = t.branchName AND target = t.target
);

